import React, { useState, useMemo, useEffect } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../common/InputText";
import CountryCity from "../../../common/Country-City";
import UserService from "../../services/users.service";
import { Error, required, PageMode } from "../../../common/Utilitis";

function AddUpdateForm(props) {
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState();
  const [selectedCountry, setSelectedCountry] = useState(
    props.selectedUser?.countryOfResidence
  );
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  const onSubmit = async (values) => {
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    // await sleep(1500);
    // calling update profile API
    const userData = {
      firstName: values.firstName,
      lastName: values.lastName,
      dateOfBirth: values.dateOfBirth,
      phone: values.phone,
      gender: values.gender,
      nationality: values.nationality,
      countryOfResidence: values.countryOfResidence,
      cityOfResidence: values.cityOfResidence,
    };
    let response;
    if (props.mode === PageMode.Update) {
      response = await UserService.updateUser(
        props.selectedUser?.userId,
        userData
      );
    } else {
      userData.password =
        userData.firstName.toLowerCase() + userData.lastName.toLowerCase();
      userData.email = values.email;
      response = await UserService.createUser(userData);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    props.onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.firstName) {
      errors.firstName = required;
    }
    if (!values.lastName) {
      errors.lastName = required;
    }
    if (!values.email) {
      errors.email = required;
    } else if (
      !values.email
        .toLowerCase()
        .match(
          /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        )
    ) {
      errors.email = "Invalid Email format!";
    }
    if (!values.phone) {
      errors.phone = required;
    }
    if (!values.gender) {
      errors.gender = required;
    }
    if (!values.dateOfBirth) {
      errors.dateOfBirth = required;
    }
    if (!values.nationality) {
      errors.nationality = required;
    }
    if (!values.countryOfResidence) {
      errors.countryOfResidence = required;
    }
    if (!values.cityOfResidence) {
      errors.cityOfResidence = required;
    }
    return errors;
  };

  const optionsCountryList = useMemo(() => CountryCity.getCountriesList(), []);

  let userForm = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        firstName: props.selectedUser?.firstName,
        lastName: props.selectedUser?.lastName,
        dateOfBirth: props.selectedUser?.dateOfBirth?.split("T")[0],
        email: props.selectedUser?.email,
        phone: props.selectedUser?.phone,
        gender: props.selectedUser?.gender,
        nationality: props.selectedUser?.nationality,
        countryOfResidence: props.selectedUser?.countryOfResidence,
        cityOfResidence: props.selectedUser?.cityOfResidence,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message && (
            <div className="invalid-feedback d-block mb-2">{message}</div>
          )}
          <div className="row form-row">
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>First Name</label>
                <Field
                  name="firstName"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Last Name</label>
                <Field
                  name="lastName"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Date of Birth</label>
                <div className="">
                  <Field
                    name="dateOfBirth"
                    className="form-control floating datetimepicker"
                    type="date"
                    component={InputField}
                  />
                </div>
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Email ID</label>
                <Field
                  name="email"
                  className="form-control floating"
                  type="email"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Mobile</label>
                <Field
                  name="phone"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Gender</label>
                <div className="col-md-10">
                  <div className="radio">
                    <Field
                      id="male_radio"
                      name="gender"
                      value="Male"
                      type="radio"
                      component={InputField}
                      hideerror="true"
                    />
                    <label htmlFor="male_radio">Male</label>
                  </div>
                  <div className="radio">
                    <Field
                      id="male_radio"
                      name="gender"
                      value="Female"
                      type="radio"
                      component={InputField}
                      hideerror="true"
                    />
                    <label htmlFor="female_radio">Female</label>
                  </div>
                  <Error name={"gender"} showerrorbeside="true" />
                </div>
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Nationality</label>
                <Field name="nationality" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.nationality}
                        {...input.select}
                        onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                        }}
                      >
                        <option value="">Select Your Nationality</option>
                        {optionsCountryList.map((val, index) => (
                          <option key={index} value={val.isoCode}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"nationality"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Country</label>
                <Field name="countryOfResidence" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.countryOfResidence}
                        {...input.select}
                        onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                          setSelectedCountry(e.target.value);
                        }}
                      >
                        <option value="">Select Country</option>
                        {optionsCountryList.map((val, index) => (
                          <option key={index} value={val.isoCode}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"countryOfResidence"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>City</label>
                <Field name="cityOfResidence" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.cityOfResidence}
                        {...input.select}
                        onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                        }}
                      >
                        <option value="">Select City</option>
                        {CountryCity.getCitiesOfCountry(selectedCountry).map(
                          (val, index) => (
                            <option key={index} value={val.name}>
                              {val.name}
                            </option>
                          )
                        )}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"cityOfResidence"} showerrorbeside="true" />
              </div>
            </div>
          </div>
          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? `Save` : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
            <button
              className="btn btn-secondary submit-btn"
              onClick={() => {
                props.onClose(null);
              }}
            >
              Close
            </button>
          </div>
        </form>
      )}
    />
  );

  return <div>{userForm}</div>;
}
export default AddUpdateForm;
