import React, { useState, useEffect } from "react";
import { Modal } from "react-bootstrap";
import UserService from "../../services/users.service";
import CircularProgress from "@mui/material/CircularProgress";
import CountryCity from "../../../common/Country-City";
import AddUpdateForm from "./AddUpdateForm";
import { PageMode } from "../../../common/Utilitis";
import DataTable from "../../../common/DataTable";
import Alert from "@mui/material/Alert";
import DashboardSidebar from "../../../client/components/dashboard/sidebar/sidebar.jsx";
import StickyBox from "react-sticky-box";
function UsersList() {
  const [loading, setLoading] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [show, setShow] = useState(false);
  const [showDelete, setShowDelete] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [message, setMessage] = useState();
  const [messageDelete, setMessageDelete] = useState();
  const [usersData, setUsersData] = useState();
  const [selectedUser, setSelectedUser] = useState(null);
  const [page, setPage] = useState(1);
  const [dataPage, setDataPage] = useState();
  const [pageIndex, setPageIndex] = useState(0);
  const [mode, setMode] = useState(PageMode.Add);
  const handleClose = () => setShow(false);
  const handleShow = () => {
    setShow(true);
    setShowSuccess(false);
  };
  const handleCloseDelete = () => setShowDelete(false);
  const handleShowDelete = () => {
    setShowDelete(true);
    setShowSuccess(false);
  };

  useEffect(async () => {
    setLoading(true);
    const response = await UserService.getAllUsers(pageIndex, 10);
    setMessage(!!response?.message && response?.message);
    if (response.success) {
      const users = response?.body?.map((user) => {
        return {
          ...user,
          name: `${user.firstName ? user.firstName : ""}${
            user.lastName ? " " + user.lastName : ""
          }`,
          nationality: CountryCity.getCountryOfCode(user.nationality)?.name,
          dateOfBirth: user.dateOfBirth?.split("T")[0],
          address: `${
            user.countryOfResidence
              ? CountryCity.getCountryOfCode(user.countryOfResidence).name
              : ""
          }${user.cityOfResidence ? ", " + user.cityOfResidence : ""}`,
        };
      });

      setUsersData(users);
      setDataPage({ ...response?.pagingation });
    }

    setLoading(false);
  }, [pageIndex]);

  const handlePageChange = (event, value) => {
    setPageIndex(value - 1);
    setPage(value);
    setShowSuccess(false);
  };

  const deleteUserHandler = async (id) => {
    setDeleting(true);

    const response = await UserService.deleteUser(id);

    setDeleting(false);
    if (!!!response.success && !response.success) {
      setMessageDelete(!!response.message && response.message);
      return;
    }
    handleCloseDelete();
    if (usersData?.length === 1) {
      setPageIndex(pageIndex - 1);
    }

    setUsersData(usersData.filter((u) => u.userId != id));
  };

  const columns = [
    { id: "name", label: "Name" },
    { id: "email", label: "Email" },
    { id: "dateOfBirth", label: "Date of Birth" },
    { id: "phone", label: "Phone", className: "text-center" },
    { id: "gender", label: "Gender", className: "text-center" },
    { id: "nationality", label: "Nationality" },
    { id: "address", label: "Address" },
  ];
  let tableContent = (
    <>
      <DataTable
        columns={columns}
        rows={usersData}
        onPageChange={handlePageChange}
        totalPages={dataPage?.totalPages}
        page={page}
        showActions={true}
        onEdit={(user) => {
          handleShow();
          setSelectedUser(user);
          setMode(PageMode.Update);
        }}
        onDelete={(user) => {
          handleShowDelete();
          setSelectedUser(user);
          setMessageDelete(null);
        }}
      />
      {/* <table className="table table-hover table-center mb-0">
        <thead>
          <tr>
            <th>#</th>
            <th>Action</th>
            <th>Name</th>
            <th>Email</th>
            <th>Date of Birth</th>
            <th className="text-center">Phone</th>
            <th className="text-center">Gender</th>
            <th>Nationality</th>
            <th>Address</th>
          </tr>
        </thead>
        <tbody>
          {usersData &&
            usersData.map((user, i) => (
              <tr key={i}>
                <td>{i + 1}</td>
                <td>
                  <div className="table-action">
                    <a
                      onClick={() => {
                        handleShow();
                        setSelectedUser(user);
                        setMode(PageMode.Update);
                      }}
                      className="btn btn-sm bg-info-light"
                      data-toggle="modal"
                      title="edit"
                    >
                      <i className="fas fa-edit" />
                    </a>
                    <a
                      onClick={() => {
                        handleShowDelete();
                        setSelectedUser(user);
                        setMessageDelete(null);
                      }}
                      className="btn btn-sm bg-danger-light"
                      title="delete"
                    >
                      <i className="fas fa-trash-alt" />
                    </a>
                  </div>
                </td>
                <td>{`${user.firstName ? user.firstName : ""}${
                  user.lastName ? " " + user.lastName : ""
                }`}</td>
                <td>{user.email}</td>
                <td>{user.dateOfBirth?.split("T")[0]}</td>
                <td className="text-center">{user.phone}</td>
                <td className="text-center">{user.gender}</td>
                <td>
                  {user.nationality
                    ? CountryCity.getCountryOfCode(user.nationality).name
                    : ""}
                </td>
                <td>{`${
                  user.countryOfResidence
                    ? CountryCity.getCountryOfCode(user.countryOfResidence).name
                    : ""
                }${
                  user.cityOfResidence ? ", " + user.cityOfResidence : ""
                }`}</td>
              </tr>
            ))}
        </tbody>
      </table>
      <Pagination
        className="centered"
        count={dataPage?.totalPages}
        variant="outlined"
        shape="rounded"
        showFirstButton
        showLastButton
        page={page}
        onChange={handlePageChange}
      /> */}
    </>
  );

  return (
    <div>
      <div className="content">
        <div className="container-fluid">
          <div className="row">
            <div className="col-md-5 col-lg-4 col-xl-3 theiaStickySidebar">
              <StickyBox offsetTop={20} offsetBottom={20}>
                <DashboardSidebar />
              </StickyBox>
            </div>
            <div className="col-md-7 col-lg-8 col-xl-9">
              <div className="row">
                <div className="col-sm-12">
                  <div className="card">
                    <div className="card-header">
                      <h4 className="card-title float-left">Users List</h4>
                      <button
                        className="btn btn-primary float-right"
                        onClick={() => {
                          handleShow();
                          setSelectedUser(null);
                          setMode(PageMode.Add);
                        }}
                        data-toggle="modal"
                      >
                        Add
                      </button>
                    </div>
                    <div className="card-body ">
                      <div className="card card-table mb-0">
                        <div className="card-body">
                          <div className="table-responsive">
                            {message && (
                              <div className="invalid-feedback d-block mb-2">
                                {message}
                              </div>
                            )}
                            {loading ? (
                              <div className="centered">
                                <h4>
                                  <div>
                                    <CircularProgress />
                                  </div>
                                  <div>
                                    <span style={{ color: "#15558d" }}>
                                      getting users...
                                    </span>
                                  </div>
                                </h4>
                              </div>
                            ) : (
                              <>
                                {showSuccess ? (
                                  <div style={{ margin: "20px" }}>
                                    <Alert severity="success">{`User have been ${mode} successfully!`}</Alert>
                                  </div>
                                ) : (
                                  <></>
                                )}
                                {tableContent}
                              </>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Modal
        show={show}
        onHide={handleClose}
        size="lg"
        scrollable={true}
        aria-labelledby="example-modal-sizes-title-sm"
      >
        <Modal.Header>
          <h5 className="modal-title">{`${mode} User`}</h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleClose}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            <div>
              <AddUpdateForm
                selectedUser={selectedUser}
                mode={mode}
                onClose={(user) => {
                  handleClose();
                  if (user) {
                    if (mode === PageMode.Update) {
                      const updatedUsers = usersData.map((u) => {
                        return u.userId === user.userId
                          ? {
                              ...user,
                              name: `${user.firstName ? user.firstName : ""}${
                                user.lastName ? " " + user.lastName : ""
                              }`,
                              nationality: CountryCity.getCountryOfCode(
                                user.nationality
                              )?.name,
                              dateOfBirth: user.dateOfBirth?.split("T")[0],
                              address: `${
                                user.countryOfResidence
                                  ? CountryCity.getCountryOfCode(
                                      user.countryOfResidence
                                    ).name
                                  : ""
                              }${
                                user.cityOfResidence
                                  ? ", " + user.cityOfResidence
                                  : ""
                              }`,
                            }
                          : u;
                      });
                      setUsersData(updatedUsers);
                    } else {
                      const addedUser = {
                        ...user,
                        name: `${user.firstName ? user.firstName : ""}${
                          user.lastName ? " " + user.lastName : ""
                        }`,
                        nationality: CountryCity.getCountryOfCode(
                          user.nationality
                        )?.name,
                        dateOfBirth: user.dateOfBirth?.split("T")[0],
                        address: `${
                          user.countryOfResidence
                            ? CountryCity.getCountryOfCode(
                                user.countryOfResidence
                              ).name
                            : ""
                        }${
                          user.cityOfResidence
                            ? ", " + user.cityOfResidence
                            : ""
                        }`,
                      };
                      if (usersData?.length === 10) {
                        setDataPage({
                          ...dataPage,
                          totalPages: dataPage.totalPages + 1,
                        });
                      }
                      setUsersData([...usersData, addedUser]);
                    }
                    setShowSuccess(true);
                  }
                }}
              />
            </div>
          </div>
        </Modal.Body>
      </Modal>

      <Modal
        show={showDelete}
        onHide={handleCloseDelete}
        aria-labelledby="example-modal-sizes-title-sm"
        centered
      >
        <Modal.Header>
          <h5 className="modal-title">Delete User Confirmation</h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleCloseDelete}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            {messageDelete && (
              <div className="invalid-feedback d-block mb-2">
                {messageDelete}
              </div>
            )}
            <h5 style={{ color: "red" }}>
              Are you sure you want to delete the following user?
            </h5>
            <div>
              <b>User Name:</b>
              {` ${selectedUser?.firstName ? selectedUser?.firstName : ""} ${
                selectedUser?.lastName ? selectedUser?.lastName : ""
              }`}
            </div>
            <div>
              <b>User Email:</b>
              {` ${selectedUser?.email}`}
            </div>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <button
            className="btn btn-danger submit-btn"
            disabled={deleting}
            onClick={() => {
              deleteUserHandler(selectedUser.userId);
            }}
          >
            {!deleting ? `Delete` : ""}
            {deleting && (
              <span className="spinner-border spinner-border-sm mb-1"></span>
            )}
          </button>
          <button
            className="btn btn-secondary submit-btn"
            onClick={handleCloseDelete}
          >
            Close
          </button>
        </Modal.Footer>
      </Modal>
    </div>
  );
}
export default UsersList;
